    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // 2. Use the buffer_adaptor's copy function to preview the first byte (data_type) without advancing the read pointer
    adaptor.copy(&result.data_type);

    // 3. Calculate the total data size needed for items: item_count * sizeof(item) based on data_type
    uint32_t item_count;
