    // After allocation: free list has element_count - 2 blocks

    // Deallocate first block - calls deallocate() which internally calls push()
    allocator.deallocate(block1);
    // After deallocation: free list has element_count - 1 blocks again

    // Deallocate second block
    allocator.deallocate(block2);
    // After deallocation: free list has element_count blocks again

    // Demonstrate LIFO behavior by showing that deallocated blocks
    // are added to the head of the free list
    int* block3 = allocator.allocate();
    // This block was previously deallocated last, so it becomes the new head
    // of the free list after reallocation
}
```

