std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> writer(buffer);

    // Check available space before writing
    if (writer.free() < input_data.size()) {
        // Handle insufficient space (resize buffer or throw error)
        buffer.resize(input_data.size());
        writer = hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>>(buffer);
    }

    // Write data to the buffer
    writer.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor for the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer);

    // Check readable size
    if (reader.size() < input_data.size()) {
        // Handle insufficient data
        return {};
    }

    // Read data back from the buffer
    std::vector<uint8_t> output_data(input_data.size());
    reader.read(output_data.data(), input_data.size());

    return output_data;
}

